import pandas as pd
import numpy as np

# 使用已暂存的区县小时空气质量数据与已解析区县ID；不写入任务最终输出变量，由综合环节统一赋值
missing_ap_inputs = []
for _v in ["district_air_obs_da_df", "district_id_zhengding_da", "district_id_xingtang_da", "analysis_date_da", "start_ts_da", "end_ts_da"]:
    try:
        eval(_v)
    except NameError:
        missing_ap_inputs.append(_v)

if missing_ap_inputs:
    ap_county_level_means_status = {
        "status": "missing_staged_inputs",
        "missing": missing_ap_inputs,
        "message": "缺少数据采集环节暂存的必要变量，未重新解析或猜测区县ID。"
    }
    print("无法计算：缺少必要暂存变量 =", missing_ap_inputs)
else:
    ap_obs = district_air_obs_da_df.copy()
    ap_obs["timestamp"] = pd.to_datetime(ap_obs["timestamp"])
    ap_start = pd.to_datetime(start_ts_da)
    ap_end = pd.to_datetime(end_ts_da)
    ap_ids = [district_id_zhengding_da, district_id_xingtang_da]
    ap_obs_day_two_counties = ap_obs[
        (ap_obs["district_id"].isin(ap_ids)) &
        (ap_obs["timestamp"] >= ap_start) &
        (ap_obs["timestamp"] < ap_end)
    ].copy()

    ap_county_level_means_df = (
        ap_obs_day_two_counties
        .groupby("district_id", as_index=False)
        .agg(
            hourly_records=("timestamp", "count"),
            valid_pm25_hours=("pm2_5", "count"),
            valid_no2_hours=("no2", "count"),
            mean_pm25=("pm2_5", "mean"),
            mean_no2=("no2", "mean"),
            peak_pm25=("pm2_5", "max"),
            peak_no2=("no2", "max"),
            min_pm25=("pm2_5", "min"),
            min_no2=("no2", "min")
        )
    )

    ap_county_label_map = {
        district_id_zhengding_da: "正定县",
        district_id_xingtang_da: "行唐县"
    }
    ap_county_level_means_df["county"] = ap_county_level_means_df["district_id"].map(ap_county_label_map)
    ap_county_level_means_df = ap_county_level_means_df[
        ["county", "district_id", "hourly_records", "valid_pm25_hours", "valid_no2_hours",
         "mean_pm25", "mean_no2", "peak_pm25", "peak_no2", "min_pm25", "min_no2"]
    ]

    def _get_mean(county_id, pollutant):
        s = ap_county_level_means_df.loc[ap_county_level_means_df["district_id"] == county_id, pollutant]
        return None if s.empty or pd.isna(s.iloc[0]) else float(s.iloc[0])

    ap_mean_pm25_zhengding_value = _get_mean(district_id_zhengding_da, "mean_pm25")
    ap_mean_no2_zhengding_value = _get_mean(district_id_zhengding_da, "mean_no2")
    ap_mean_pm25_xingtang_value = _get_mean(district_id_xingtang_da, "mean_pm25")
    ap_mean_no2_xingtang_value = _get_mean(district_id_xingtang_da, "mean_no2")

    ap_spatial_gradient_metrics = {}
    if ap_mean_pm25_zhengding_value is not None and ap_mean_pm25_xingtang_value is not None:
        ap_spatial_gradient_metrics["pm25_zhengding_minus_xingtang"] = ap_mean_pm25_zhengding_value - ap_mean_pm25_xingtang_value
        ap_spatial_gradient_metrics["pm25_higher_county"] = "正定县" if ap_mean_pm25_zhengding_value > ap_mean_pm25_xingtang_value else ("行唐县" if ap_mean_pm25_xingtang_value > ap_mean_pm25_zhengding_value else "两县相同")
    if ap_mean_no2_zhengding_value is not None and ap_mean_no2_xingtang_value is not None:
        ap_spatial_gradient_metrics["no2_zhengding_minus_xingtang"] = ap_mean_no2_zhengding_value - ap_mean_no2_xingtang_value
        ap_spatial_gradient_metrics["no2_higher_county"] = "正定县" if ap_mean_no2_zhengding_value > ap_mean_no2_xingtang_value else ("行唐县" if ap_mean_no2_xingtang_value > ap_mean_no2_zhengding_value else "两县相同")

    ap_hourly_pivot = ap_obs_day_two_counties.pivot_table(
        index="timestamp", columns="district_id", values=["pm2_5", "no2"], aggfunc="mean"
    )
    ap_temporal_gradient_summary = {}
    if len(ap_hourly_pivot) > 0:
        if ("pm2_5", district_id_zhengding_da) in ap_hourly_pivot.columns and ("pm2_5", district_id_xingtang_da) in ap_hourly_pivot.columns:
            ap_pm25_diff_series = ap_hourly_pivot[("pm2_5", district_id_zhengding_da)] - ap_hourly_pivot[("pm2_5", district_id_xingtang_da)]
            ap_temporal_gradient_summary["pm25_hours_zhengding_higher"] = int((ap_pm25_diff_series > 0).sum())
            ap_temporal_gradient_summary["pm25_hours_xingtang_higher"] = int((ap_pm25_diff_series < 0).sum())
            ap_temporal_gradient_summary["pm25_hours_equal"] = int((ap_pm25_diff_series == 0).sum())
        if ("no2", district_id_zhengding_da) in ap_hourly_pivot.columns and ("no2", district_id_xingtang_da) in ap_hourly_pivot.columns:
            ap_no2_diff_series = ap_hourly_pivot[("no2", district_id_zhengding_da)] - ap_hourly_pivot[("no2", district_id_xingtang_da)]
            ap_temporal_gradient_summary["no2_hours_zhengding_higher"] = int((ap_no2_diff_series > 0).sum())
            ap_temporal_gradient_summary["no2_hours_xingtang_higher"] = int((ap_no2_diff_series < 0).sum())
            ap_temporal_gradient_summary["no2_hours_equal"] = int((ap_no2_diff_series == 0).sum())

    ap_spatial_pollution_pattern_summary = {
        "date": analysis_date_da,
        "county_means": {
            "zhengding": {"pm2_5": ap_mean_pm25_zhengding_value, "no2": ap_mean_no2_zhengding_value},
            "xingtang": {"pm2_5": ap_mean_pm25_xingtang_value, "no2": ap_mean_no2_xingtang_value}
        },
        "between_county_gradient": ap_spatial_gradient_metrics,
        "hourly_dominance_counts": ap_temporal_gradient_summary
    }

    print("区县小时记录与均值汇总：")
    print(ap_county_level_means_df.round(3).to_string(index=False))
    print("两县空间梯度指标：", {k: (round(v, 3) if isinstance(v, float) else v) for k, v in ap_spatial_gradient_metrics.items()})
    print("逐小时高值占优统计：", ap_temporal_gradient_summary)
